import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int maxLength = 10; // Maximum length for the buffer
        char[] buffer = new char[maxLength];

        // Ensure that user input does not exceed the maximum length
        if (userInput.length() > maxLength) {
            System.out.println("Input exceeds maximum allowed length.");
            return;
        }

        // Copy user input into buffer
        userInput.getChars(0, Math.min(userInput.length(), maxLength), buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
